import{_ as o,o as i,c as l,al as n}from"./chunks/framework.DPRzuwkw.js";const p=JSON.parse('{"title":"Environment Setup","description":"","frontmatter":{},"headers":[],"relativePath":"en/posts/docs/addon/01_environment.md","filePath":"en/posts/docs/addon/01_environment.md","lastUpdated":1773836152000}'),a={name:"en/posts/docs/addon/01_environment.md"};function r(t,e,d,c,s,m){return i(),l("div",null,[...e[0]||(e[0]=[n('<h1 id="environment-setup" tabindex="-1">Environment Setup <a class="header-anchor" href="#environment-setup" aria-label="Permalink to “Environment Setup”">​</a></h1><h2 id="i-prerequisites" tabindex="-1">I. Prerequisites <a class="header-anchor" href="#i-prerequisites" aria-label="Permalink to “I. Prerequisites”">​</a></h2><ol><li>Install <code>IntelliJ IDEA</code></li><li>Install <code>IntelliJ IDEA</code> plugins: <ul><li><a href="https://plugins.jetbrains.com/plugin/8327-minecraft-development" target="_blank" rel="noreferrer">Minecraft Development</a></li></ul></li></ol><h2 id="ii-create-repository-from-addon-template" tabindex="-1">II. Create Repository from Addon Template <a class="header-anchor" href="#ii-create-repository-from-addon-template" aria-label="Permalink to “II. Create Repository from Addon Template”">​</a></h2><ol><li>Open the <a href="https://github.com/Anvil-Dev/AnvilCraftAddonTemplate" target="_blank" rel="noreferrer">Addon Template Repository</a>, click <code>Use this template</code> in the top right corner, and select <code>Create a new repository</code>;</li><li>Enter the relevant information for your addon mod on the new page, such as name and description. We recommend naming it in the format <code>AnvilCraft-${AddonName}</code>, for example <code>AnvilCraft-Demo</code>;</li><li>Clone the repository to your local machine; <ul><li>Please search for instructions on how to do this</li></ul></li></ol><h2 id="iii-build-environment" tabindex="-1">III. Build Environment <a class="header-anchor" href="#iii-build-environment" aria-label="Permalink to “III. Build Environment”">​</a></h2><ol><li>Open the cloned repository directory with <code>IntelliJ IDEA</code></li><li>Open <code>gradle.properties</code> and modify it with your mod information: <ul><li><code>maven_group</code><ul><li>Maven group</li><li>Usually the main package name</li><li>Recommended to use <code>dev.anvilcraft.${addonId}</code></li><li>Example: <code>dev.anvilcraft.demo</code></li></ul></li><li><code>mod_id</code><ul><li>Mod ID</li><li>Recommended to use <code>anvilcraft_addonId</code></li><li>Example: <code>anvilcraft_demo</code></li></ul></li><li><code>mod_name</code><ul><li>Mod name</li><li>Recommended to use <code>AnvilCraft-${AddonName}</code></li><li>Example: <code>AnvilCraft-Demo</code></li></ul></li><li><code>mod_description</code><ul><li>Mod description</li></ul></li><li><code>mod_license</code><ul><li>Mod open source license, recommended to use <code>LGPL-3.0 license</code></li><li>If you directly include AnvilCraft source code or modified AnvilCraft source code, this must be <code>LGPL-3.0 license</code></li></ul></li><li><code>mod_version</code><ul><li>Mod version number</li></ul></li><li><code>mod_authors</code><ul><li>Mod authors</li></ul></li></ul></li><li>Modify dependency information in <code>gradle/libs.versions.toml</code>: <ul><li><code>versions</code>.<code>anvilCraft</code><ul><li>AnvilCraft version number</li><li>You can check the latest version at <a href="https://server.cjsah.net:1002/maven/dev/dubhe/anvilcraft-neoforge-1.21.1/maven-metadata.xml" target="_blank" rel="noreferrer">this link</a></li></ul></li></ul></li><li>Modify the package name in the following paths to your own package name: <ul><li><code>src/main/java</code></li><li>Example: <code>dev.anvilcraft.addon.demo</code></li></ul></li><li>Modify <code>MOD_ID</code> in <code>AnvilCraftAddonTemplate.java</code> to your own mod id <ul><li>Example: <code>anvilcraft_demo</code></li></ul></li><li>Rename <code>AnvilCraftAddonTemplate.java</code> to your own MOD class name <ul><li>Example: <code>AnvilCraftDemo.java</code></li></ul></li><li>Rename <code>AnvilCraftAddonTemplateClient.java</code> to your own MOD class name <ul><li>Example: <code>AnvilCraftDemoClient.java</code></li></ul></li><li>Rename <code>src/main/resources/anvilcraft_addon_template.mixins.json</code> to your own MOD mixins json name <ul><li>Example: <code>src/main/resources/anvilcraft_demo.mixins.json</code></li></ul></li><li>Rename <code>src/main/resources/assets/anvilcraft_addon_template</code> to your own MOD resource pack namespace <ul><li>Example: <code>src/main/resources/assets/anvilcraft_demo</code></li></ul></li><li>Reload Gradle scripts</li><li>Run the <code>Tasks -&gt; loom -&gt; dataCopy</code> task</li><li>Run the <code>Tasks -&gt; loom -&gt; genSources</code> task</li><li>Reload Gradle scripts</li><li>Your development environment is now fully ready</li></ol><h2 id="iv-verify-environment" tabindex="-1">IV. Verify Environment <a class="header-anchor" href="#iv-verify-environment" aria-label="Permalink to “IV. Verify Environment”">​</a></h2><ol><li><p>Run the <code>Tasks -&gt; neoforge runs -&gt; runClient</code> task to test the environment</p><ul><li>If Minecraft starts normally and you can see your mod, the environment is configured successfully</li></ul></li><li><p>Check log output</p><ul><li>Confirm there are no error messages</li><li>Verify that the mod is loaded correctly</li></ul></li></ol><h2 id="v-common-issues-and-solutions" tabindex="-1">V. Common Issues and Solutions <a class="header-anchor" href="#v-common-issues-and-solutions" aria-label="Permalink to “V. Common Issues and Solutions”">​</a></h2><ol><li><p><strong>Gradle Sync Failed</strong></p><ul><li>Check your network connection and ensure you can access Maven repositories</li><li>Try using the <code>./gradlew --refresh-dependencies</code> command to refresh dependencies</li></ul></li><li><p><strong>Cannot Find AnvilCraft Dependency</strong></p><ul><li>Check the latest version number in the <a href="https://server.cjsah.net:1002/maven/dev/dubhe/anvilcraft-neoforge-1.21.1/maven-metadata.xml" target="_blank" rel="noreferrer">Maven Repository</a></li><li>Ensure the version number matches your Minecraft version</li></ul></li><li><p><strong>IDEA Cannot Recognize Project</strong></p><ul><li>Delete the <code>.idea</code> folder and <code>*.iml</code> files, then re-import the project</li><li>Ensure you have selected the correct JDK version (Java 21)</li></ul></li></ol>',11)])])}const h=o(a,[["render",r]]);export{p as __pageData,h as default};
